+fn deferred_module_set(manifest: &Value) -> HashSet<String> {
+    as_array(manifest, "/deferred_modules")
+        .iter()
+        .filter_map(|entry| {
+            entry
+                .get("module_path")
+                .and_then(Value::as_str)
+                .map(str::trim)
+                .filter(|path| !path.is_empty())
+                .map(ToOwned::to_owned)
+        })
+        .collect()
+}
